            //            "sourceExchanges":  [ "huobi", "Okex", "Binance", "Kucoin", "Poloniex", "Hitbtc" ],
            //            "premiumsSymbol1M": ".ETHUSDTMPI",
            //            "premiumsSymbol8H": ".ETHUSDTMPI8H",
            //            "fundingBaseSymbol1M": ".ETHINT",
