    /**
     * @method
     * @name kucoinfutures#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://www.kucoin.com/docs/rest/futures-trading/market-data/get-klines
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, 200)).join();
            }
            Object market = this.market(symbol);
            Object marketId = Helpers.GetValue(market, "id");
            Object parsedTimeframe = this.safeInteger(this.timeframes, timeframe);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", marketId );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(parsedTimeframe, null)))
            {
                Helpers.addElementToObject(request, "granularity", parsedTimeframe);
            } else
            {
                Helpers.addElementToObject(request, "granularity", timeframe);
            }
            Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
            Object endAt = this.milliseconds();
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", since);
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = this.safeInteger(this.options, "fetchOHLCVLimit", 200);
                }
                endAt = this.sum(since, Helpers.multiply(limit, duration));
            } else if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                since = Helpers.subtract(endAt, Helpers.multiply(limit, duration));
                Helpers.addElementToObject(request, "from", since);
            }
            Helpers.addElementToObject(request, "to", endAt);
            Object response = (this.futuresPublicGetKlineQuery(this.extend(request, parameters))).join();
            //
            //    {
            //        "code": "200000",
            //        "data": [
            //            [1636459200000, 4779.3, 4792.1, 4768.7, 4770.3, 78051],
            //            [1636460100000, 4770.25, 4778.55, 4757.55, 4777.25, 80164],
            //            [1636461000000, 4777.25, 4791.45, 4774.5, 4791.3, 51555]
            //        ]
            //    }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(data, market, timeframe, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //    [
        //        "1545904980000",          // Start time of the candle cycle
        //        "0.058",                  // opening price
        //        "0.049",                  // closing price
        //        "0.058",                  // highest price
        //        "0.049",                  // lowest price
        //        "0.018",                  // base volume
        //        "0.000945",               // quote volume
        //    ]
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, 0), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 4), this.safeNumber(ohlcv, 5)));
    }

