    /**
     * @method
     * @name kucoinfutures#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://www.kucoin.com/docs/rest/futures-trading/market-data/get-part-order-book-level-2
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object level = this.safeNumber(parameters, "level");
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(level, 2)) && Helpers.isTrue(!Helpers.isEqual(level, null))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " fetchOrderBook() can only return level 2")) ;
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(limit, 20))) || Helpers.isTrue((Helpers.isEqual(limit, 100)))))
                {
                    Helpers.addElementToObject(request, "limit", limit);
                } else
                {
                    throw new BadRequest((String)Helpers.add(this.id, " fetchOrderBook() limit argument must be 20 or 100")) ;
                }
            } else
            {
                Helpers.addElementToObject(request, "limit", 20);
            }
            Object response = (this.futuresPublicGetLevel2DepthLimit(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "200000",
            //         "data": {
            //           "symbol": "XBTUSDM",      //Symbol
            //           "sequence": 100,          //Ticker sequence number
            //           "asks": [
            //                 ["5000.0", 1000],   //Price, quantity
            //                 ["6000.0", 1983]    //Price, quantity
            //           ],
            //           "bids": [
            //                 ["3200.0", 800],    //Price, quantity
            //                 ["3100.0", 100]     //Price, quantity
            //           ],
            //           "ts": 1604643655040584408  // timestamp
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object timestamp = this.parseToInt(Helpers.divide(this.safeInteger(data, "ts"), 1000000));
            Object orderbook = this.parseOrderBook(data, Helpers.GetValue(market, "symbol"), timestamp, "bids", "asks", 0, 1);
            Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(data, "sequence"));
            return orderbook;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

