    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // fetchOrder, fetchOrdersByStatus
        //
        //     {
        //         "id": "64507d02921f1c0001ff6892",
        //         "symbol": "XBTUSDTM",
        //         "type": "market",
        //         "side": "buy",
        //         "price": null,
        //         "size": 1,
        //         "value": "27.992",
        //         "dealValue": "27.992",
        //         "dealSize": 1,
        //         "stp": "",
        //         "stop": "",
        //         "stopPriceType": "",
        //         "stopTriggered": false,
        //         "stopPrice": null,
        //         "timeInForce": "GTC",
        //         "postOnly": false,
        //         "hidden": false,
        //         "iceberg": false,
        //         "leverage": "17",
        //         "forceHold": false,
        //         "closeOrder": false,
        //         "visibleSize": null,
        //         "clientOid": null,
        //         "remark": null,
        //         "tags": null,
        //         "isActive": false,
        //         "cancelExist": false,
        //         "createdAt": 1682996482000,
        //         "updatedAt": 1682996483062,
        //         "endAt": 1682996483062,
        //         "orderTime": 1682996482953900677,
        //         "settleCurrency": "USDT",
        //         "status": "done",
        //         "filledValue": "27.992",
        //         "filledSize": 1,
        //         "reduceOnly": false
        //     }
        //
        // createOrder
        //
        //     {
        //         "orderId": "619717484f1d010001510cde"
        //     }
        //
        // createOrders
        //
        //     {
        //         "orderId": "80465574458560512",
        //         "clientOid": "5c52e11203aa677f33e491",
        //         "symbol": "ETHUSDTM",
        //         "code": "200000",
        //         "msg": "success"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object orderId = this.safeString2(order, "id", "orderId");
        Object type = this.safeString(order, "type");
        Object timestamp = this.safeInteger(order, "createdAt");
        Object datetime = this.iso8601(timestamp);
        Object price = this.safeString(order, "price");
        // price is zero for market order
        // omitZero is called in safeOrder2
        Object side = this.safeString(order, "side");
        Object feeCurrencyId = this.safeString(order, "feeCurrency");
        Object feeCurrency = this.safeCurrencyCode(feeCurrencyId);
        Object feeCost = this.safeNumber(order, "fee");
        Object amount = this.safeString(order, "size");
        Object filled = this.safeString(order, "filledSize");
        Object cost = this.safeString(order, "filledValue");
        Object average = this.safeString(order, "avgDealPrice");
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(average, null))) && Helpers.isTrue(Precise.stringGt(filled, "0"))))
        {
            Object contractSize = this.safeString(market, "contractSize");
            if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                average = Precise.stringDiv(cost, Precise.stringMul(contractSize, filled));
            } else
            {
                average = Precise.stringDiv(Precise.stringMul(contractSize, filled), cost);
            }
        }
        // precision reported by their api is 8 d.p.
        // const average = Precise.stringDiv (cost, Precise.stringMul (filled, market['contractSize']));
        // bool
        Object isActive = this.safeValue(order, "isActive");
        Object cancelExist = this.safeBool(order, "cancelExist", false);
        Object status = null;
        if (Helpers.isTrue(!Helpers.isEqual(isActive, null)))
        {
            status = ((Helpers.isTrue(isActive))) ? "open" : "closed";
        }
        status = ((Helpers.isTrue(cancelExist))) ? "canceled" : status;
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", feeCurrency );
                put( "cost", finalFeeCost );
            }};
        }
        Object clientOrderId = this.safeString(order, "clientOid");
        Object timeInForce = this.safeString(order, "timeInForce");
        Object postOnly = this.safeValue(order, "postOnly");
        Object reduceOnly = this.safeValue(order, "reduceOnly");
        Object lastUpdateTimestamp = this.safeInteger(order, "updatedAt");
        final Object finalFee = fee;
        final Object finalStatus = status;
        final Object finalAverage = average;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "symbol", symbol );
            put( "type", type );
            put( "timeInForce", timeInForce );
            put( "postOnly", postOnly );
            put( "reduceOnly", reduceOnly );
            put( "side", side );
            put( "amount", amount );
            put( "price", price );
            put( "triggerPrice", Kucoinfutures.this.safeNumber(order, "stopPrice") );
            put( "cost", cost );
            put( "filled", filled );
            put( "remaining", null );
            put( "timestamp", timestamp );
            put( "datetime", datetime );
            put( "fee", finalFee );
            put( "status", finalStatus );
            put( "info", order );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", lastUpdateTimestamp );
            put( "average", finalAverage );
            put( "trades", null );
        }}, market);
    }

