            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", Kucoinfutures.this.safeNumber(data, "value") );
            put( "fundingTimestamp", fundingTimestamp );
            put( "fundingDatetime", Kucoinfutures.this.iso8601(fundingTimestamp) );
            put( "nextFundingRate", Kucoinfutures.this.safeNumber(data, "predictedValue") );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
