    /**
     * @method
     * @name kucoinfutures#transfer
     * @description transfer currency internally between wallets on the same account
     * @see https://www.kucoin.com/docs/rest/funding/transfer/transfer-to-main-or-trade-account
     * @see https://www.kucoin.com/docs/rest/funding/transfer/transfer-to-futures-account
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from
     * @param {string} toAccount account to transfer to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount, Object toAccount2, Object... optionalArgs)
    {
        final Object toAccount3 = toAccount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object toAccount = toAccount3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object amountToPrecision = this.currencyToPrecision(code, amount);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency", Kucoinfutures.this.safeString(currency, "id") );
                put( "amount", amountToPrecision );
            }};
            Object toAccountString = this.parseTransferType(toAccount);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(toAccountString, "TRADE")) || Helpers.isTrue(Helpers.isEqual(toAccountString, "MAIN"))))
            {
                Helpers.addElementToObject(request, "recAccountType", toAccountString);
                response = (this.futuresPrivatePostTransferOut(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(toAccount, "future")) || Helpers.isTrue(Helpers.isEqual(toAccount, "swap"))) || Helpers.isTrue(Helpers.isEqual(toAccount, "contract"))))
            {
                Helpers.addElementToObject(request, "payAccountType", this.parseTransferType(fromAccount));
                response = (this.futuresPrivatePostTransferIn(this.extend(request, parameters))).join();
            } else
            {
                throw new BadRequest((String)Helpers.add(this.id, " transfer() only supports transfers between future/swap, spot and funding accounts")) ;
            }
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            final Object finalToAccount = toAccount;
            return this.extend(this.parseTransfer(data, currency), new java.util.HashMap<String, Object>() {{
                put( "amount", Kucoinfutures.this.parseNumber(amountToPrecision) );
                put( "fromAccount", fromAccount );
                put( "toAccount", finalToAccount );
            }});
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // transfer to spot or funding account
        //
        //     {
        //            "applyId": "5bffb63303aa675e8bbe18f9" // Transfer-out request ID
        //     }
        //
        // transfer to future account
        //
        //     {
        //         "applyId": "6738754373ceee00011ec3f8",
        //         "bizNo": "6738754373ceee00011ec3f7",
        //         "payAccountType": "CONTRACT",
        //         "payTag": "DEFAULT",
        //         "remark": "",
        //         "recAccountType": "MAIN",
        //         "recTag": "DEFAULT",
        //         "recRemark": "",
        //         "recSystem": "KUCOIN",
        //         "status": "PROCESSING",
        //         "currency": "USDT",
        //         "amount": "5",
        //         "fee": "0",
        //         "sn": 1519769124846692,
        //         "reason": "",
        //         "createdAt": 1731753283000,
        //         "updatedAt": 1731753283000
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transfer, "updatedAt");
        return new java.util.HashMap<String, Object>() {{
            put( "id", Kucoinfutures.this.safeString(transfer, "applyId") );
            put( "timestamp", timestamp );
            put( "datetime", Kucoinfutures.this.iso8601(timestamp) );
            put( "currency", Kucoinfutures.this.safeCurrencyCode(null, currency) );
            put( "amount", Kucoinfutures.this.safeNumber(transfer, "amount") );
            put( "fromAccount", null );
            put( "toAccount", null );
            put( "status", Kucoinfutures.this.safeString(transfer, "status") );
            put( "info", transfer );
        }};
    }

