    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "sequence": 32114961,
        //         "side": "buy",
        //         "size": 39,
        //         "price": "4001.6500000000",
        //         "takerOrderId": "61c20742f172110001e0ebe4",
        //         "makerOrderId": "61c2073fcfc88100010fcb5d",
        //         "tradeId": "61c2074277a0c473e69029b8",
        //         "ts": 1640105794099993896   // filled time
        //     }
        //
        // fetchMyTrades (private) v2
        //
        //     {
        //         "symbol":"BTC-USDT",
        //         "tradeId":"5c35c02709e4f67d5266954e",
        //         "orderId":"5c35c02703aa673ceec2a168",
        //         "counterOrderId":"5c1ab46003aa676e487fa8e3",
        //         "side":"buy",
        //         "liquidity":"taker",
        //         "forceTaker":true,
        //         "price":"0.083",
        //         "size":"0.8424304",
        //         "funds":"0.0699217232",
        //         "fee":"0",
        //         "feeRate":"0",
        //         "feeCurrency":"USDT",
        //         "stop":"",
        //         "type":"limit",
        //         "createdAt":1547026472000
        //     }
        //
        // fetchMyTrades (private) v1
        //
        //    {
        //        "symbol":"DOGEUSDTM",
        //        "tradeId":"620ec41a96bab27b5f4ced56",
        //        "orderId":"620ec41a0d1d8a0001560bd0",
        //        "side":"sell",
        //        "liquidity":"taker",
        //        "forceTaker":true,
        //        "price":"0.13969",
        //        "size":1,
        //        "value":"13.969",
        //        "feeRate":"0.0006",
        //        "fixFee":"0",
        //        "feeCurrency":"USDT",
        //        "stop":"",
        //        "tradeTime":1645134874858018058,
        //        "fee":"0.0083814",
        //        "settleCurrency":"USDT",
        //        "orderType":"market",
        //        "tradeType":"trade",
        //        "createdAt":1645134874858
        //    }
        //
        // watchTrades
        //
        //    {
        //        "makerUserId": "62286a4d720edf0001e81961",
        //        "symbol": "ADAUSDTM",
        //        "sequence": 41320766,
        //        "side": "sell",
        //        "size": 2,
        //        "price": 0.35904,
        //        "takerOrderId": "636dd9da9857ba00010cfa44",
        //        "makerOrderId": "636dd9c8df149d0001e62bc8",
        //        "takerUserId": "6180be22b6ab210001fa3371",
        //        "tradeId": "636dd9da0000d400d477eca7",
        //        "ts": 1668143578987357700
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market, "-");
        Object id = this.safeString2(trade, "tradeId", "id");
        Object orderId = this.safeString(trade, "orderId");
        Object takerOrMaker = this.safeString(trade, "liquidity");
        Object timestamp = this.safeInteger(trade, "ts");
        if (Helpers.isTrue(!Helpers.isEqual(timestamp, null)))
        {
            timestamp = this.parseToInt(Helpers.divide(timestamp, 1000000));
        } else
        {
            timestamp = this.safeInteger(trade, "createdAt");
            // if it's a historical v1 trade, the exchange returns timestamp in seconds
            if (Helpers.isTrue(Helpers.isTrue((Helpers.inOp(trade, "dealValue"))) && Helpers.isTrue((!Helpers.isEqual(timestamp, null)))))
            {
                timestamp = Helpers.multiply(timestamp, 1000);
            }
        }
        Object priceString = this.safeString2(trade, "price", "dealPrice");
        Object amountString = this.safeString2(trade, "size", "amount");
        Object side = this.safeString(trade, "side");
        Object fee = null;
        Object feeCostString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "feeCurrency");
            Object feeCurrency = this.safeCurrencyCode(feeCurrencyId);
            if (Helpers.isTrue(Helpers.isEqual(feeCurrency, null)))
            {
                feeCurrency = ((Helpers.isTrue((Helpers.isEqual(side, "sell"))))) ? Helpers.GetValue(market, "quote") : Helpers.GetValue(market, "base");
            }
            final Object finalFeeCostString = feeCostString;
            final Object finalFeeCurrency = feeCurrency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", finalFeeCurrency );
                put( "rate", Kucoinfutures.this.safeString(trade, "feeRate") );
            }};
        }
        Object type = this.safeString2(trade, "type", "orderType");
        if (Helpers.isTrue(Helpers.isEqual(type, "match")))
        {
            type = null;
        }
        Object costString = this.safeString2(trade, "funds", "value");
        if (Helpers.isTrue(Helpers.isEqual(costString, null)))
        {
            Object contractSize = this.safeString(market, "contractSize");
            Object contractCost = Precise.stringMul(priceString, amountString);
            costString = Precise.stringMul(contractCost, contractSize);
        }
        final Object finalTimestamp = timestamp;
        final Object finalMarket = market;
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalCostString = costString;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "order", orderId );
            put( "timestamp", finalTimestamp );
            put( "datetime", Kucoinfutures.this.iso8601(finalTimestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", finalType );
            put( "takerOrMaker", takerOrMaker );
            put( "side", finalSide );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", finalCostString );
            put( "fee", finalFee );
        }}, market);
    }

