    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        /**
        * @ignore
        * @method
        * @name kucoinfutures#parseMarketLeverageTiers
        * @param {object} info Exchange market response for 1 market
        * @param {object} market CCXT market
        */
        //
        //    {
        //        "symbol": "ETHUSDTM",
        //        "level": 1,
        //        "maxRiskLimit": 300000,
        //        "minRiskLimit": 0,
        //        "maxLeverage": 100,
        //        "initialMargin": 0.0100000000,
        //        "maintainMargin": 0.0050000000
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(info)); i++)
        {
            Object tier = Helpers.GetValue(info, i);
            Object marketId = this.safeString(tier, "symbol");
            ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", Kucoinfutures.this.safeNumber(tier, "level") );
                put( "symbol", Kucoinfutures.this.safeSymbol(marketId, market, null, "contract") );
                put( "currency", Helpers.GetValue(market, "base") );
                put( "minNotional", Kucoinfutures.this.safeNumber(tier, "minRiskLimit") );
                put( "maxNotional", Kucoinfutures.this.safeNumber(tier, "maxRiskLimit") );
                put( "maintenanceMarginRate", Kucoinfutures.this.safeNumber(tier, "maintainMargin") );
                put( "maxLeverage", Kucoinfutures.this.safeNumber(tier, "maxLeverage") );
                put( "info", tier );
            }});
        }
        return tiers;
    }

    /**
     * @method
     * @name kucoinfutures#fetchFundingRateHistory
     * @see https://www.kucoin.com/docs/rest/futures-trading/funding-fees/get-public-funding-history#request-url
     * @description fetches historical funding rate prices
     * @param {string} symbol unified symbol of the market to fetch the funding rate history for
     * @param {int} [since] not used by kucuoinfutures
     * @param {int} [limit] the maximum amount of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure} to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] end time in ms
     * @returns {object[]} a list of [funding rate structures]{@link https://docs.ccxt.com/?id=funding-rate-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingRateHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchFundingRateHistory() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "from", 0 );
                put( "to", Kucoinfutures.this.milliseconds() );
            }};
            Object until = this.safeInteger(parameters, "until");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until")));
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", since);
                if (Helpers.isTrue(Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "to", Helpers.add(since, Helpers.multiply(Helpers.multiply(Helpers.multiply(Helpers.multiply(1000, 8), 60), 60), 100)));
                }
            }
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "to", until);
                if (Helpers.isTrue(Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "to", Helpers.subtract(until, Helpers.multiply(Helpers.multiply(Helpers.multiply(Helpers.multiply(1000, 8), 60), 60), 100)));
                }
            }
            Object response = (this.futuresPublicGetContractFundingRates(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "200000",
            //         "data": [
            //             {
            //                 "symbol": "IDUSDTM",
            //                 "fundingRate": 2.26E-4,
            //                 "timepoint": 1702296000000
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseFundingRateHistories(data, market, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseFundingRateHistory(Object info, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(info, "timepoint");
        Object marketId = this.safeString(info, "symbol");
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", Kucoinfutures.this.safeSymbol(marketId, market) );
            put( "fundingRate", Kucoinfutures.this.safeNumber(info, "fundingRate") );
            put( "timestamp", timestamp );
            put( "datetime", Kucoinfutures.this.iso8601(timestamp) );
        }};
    }

    /**
     * @method
     * @name kucoinfutures#closePosition
     * @description closes open positions for a market
     * @see https://www.kucoin.com/docs/rest/futures-trading/orders/place-order
     * @param {string} symbol Unified CCXT market symbol
     * @param {string} side not used by kucoinfutures closePositions
     * @param {object} [params] extra parameters specific to the okx api endpoint
     * @param {string} [params.clientOrderId] client order id of the order
     * @returns {object[]} [A list of position structures]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> closePosition(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object side = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            Object testOrder = this.safeBool(parameters, "test", false);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("test", "clientOrderId")));
            if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
            {
                clientOrderId = this.numberToString(this.nonce());
            }
            final Object finalClientOrderId = clientOrderId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "closeOrder", true );
                put( "clientOid", finalClientOrderId );
                put( "type", "market" );
            }};
            Object response = null;
            if (Helpers.isTrue(testOrder))
            {
                response = (this.futuresPrivatePostOrdersTest(this.extend(request, parameters))).join();
            } else
            {
                response = (this.futuresPrivatePostOrders(this.extend(request, parameters))).join();
            }
            return this.parseOrder(response, market);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

